export type O9BadgeAlertType = 'positive' | 'info' | 'neutral' | 'warning' | 'negative' | 'block';
export type O9BadgeAlertVariant = 'primary' | 'outline';
export type O9BadgeAlertSize = 'sm' | 'lg';

export interface O9BadgeAlertOptions {
  message?: string;
  type?: O9BadgeAlertType;
  variant?: O9BadgeAlertVariant;
  size?: O9BadgeAlertSize;
  icon?: boolean;
  customIcon?: string | null;
  role?: 'status' | 'alert';
}

type ResolvedOptions = Required<Omit<O9BadgeAlertOptions, 'customIcon'>> & {
  customIcon: string | null;
};

const TYPES: readonly O9BadgeAlertType[] = ['positive', 'info', 'neutral', 'warning', 'negative', 'block'];
const VARIANTS: readonly O9BadgeAlertVariant[] = ['primary', 'outline'];
const SIZES: readonly O9BadgeAlertSize[] = ['sm', 'lg'];

const DEFAULTS: ResolvedOptions = {
  message: '',
  type: 'positive',
  variant: 'primary',
  size: 'lg',
  icon: true,
  customIcon: null,
  role: 'status',
};

export class O9BadgeAlert {
  private _element: HTMLElement | null;
  private _options: ResolvedOptions;
  private _icoEl: HTMLSpanElement | null = null;
  private _msgEl: HTMLSpanElement | null = null;

  static initialize(element: HTMLElement, options?: O9BadgeAlertOptions): O9BadgeAlert {
    return new O9BadgeAlert(element, options);
  }

  constructor(element: HTMLElement, options?: O9BadgeAlertOptions) {
    this._element = element;

    this._options = {
      ...DEFAULTS,
      ...options,
      type: options?.type && (TYPES as readonly string[]).includes(options.type)
        ? options.type
        : DEFAULTS.type,
      variant: options?.variant && (VARIANTS as readonly string[]).includes(options.variant)
        ? options.variant
        : DEFAULTS.variant,
      size: options?.size && (SIZES as readonly string[]).includes(options.size)
        ? options.size
        : DEFAULTS.size,
      customIcon: options?.customIcon ?? null,
    };

    this._render();
  }

  private _render(): void {
    const el = this._element;
    if (!el) return;

    el.innerHTML = '';

    el.className = [
      'o9ds-bdg-alert',
      `o9ds-bdg-alert--${this._options.variant}`,
      `o9ds-bdg-alert--${this._options.type}`,
      `o9ds-bdg-alert--${this._options.size}`,
    ].join(' ');

    el.setAttribute('role', this._options.role);

    if (this._options.icon) {
      this._icoEl = this._createIconEl();
      el.appendChild(this._icoEl);
    } else {
      this._icoEl = null;
    }

    this._msgEl = document.createElement('span');
    this._msgEl.className = 'o9ds-bdg-alert__msg';
    this._msgEl.textContent = this._options.message;
    el.appendChild(this._msgEl);
  }

  private _createIconEl(): HTMLSpanElement {
    const span = document.createElement('span');
    const classes = ['o9ds-bdg-alert__ico', 'o9con'];
    if (this._options.customIcon) {
      classes.push(`o9con-${this._options.customIcon}`);
    }
    span.className = classes.join(' ');
    span.setAttribute('aria-hidden', 'true');
    return span;
  }

  setMessage(text: string): void {
    this._options.message = text;
    if (this._msgEl) {
      this._msgEl.textContent = text;
    }
  }

  setType(type: O9BadgeAlertType): void {
    if (!(TYPES as readonly string[]).includes(type)) return;

    const el = this._element;
    if (!el) return;

    TYPES.forEach(t => el.classList.remove(`o9ds-bdg-alert--${t}`));
    el.classList.add(`o9ds-bdg-alert--${type}`);
    this._options.type = type;
  }

  setVariant(variant: O9BadgeAlertVariant): void {
    if (!(VARIANTS as readonly string[]).includes(variant)) return;

    const el = this._element;
    if (!el) return;

    VARIANTS.forEach(v => el.classList.remove(`o9ds-bdg-alert--${v}`));
    el.classList.add(`o9ds-bdg-alert--${variant}`);
    this._options.variant = variant;
  }

  setSize(size: O9BadgeAlertSize): void {
    if (!(SIZES as readonly string[]).includes(size)) return;

    const el = this._element;
    if (!el) return;

    SIZES.forEach(s => el.classList.remove(`o9ds-bdg-alert--${s}`));
    el.classList.add(`o9ds-bdg-alert--${size}`);
    this._options.size = size;
  }

  setIcon(show: boolean): void {
    this._options.icon = show;
    const el = this._element;
    if (!el) return;

    if (show && !this._icoEl) {
      this._icoEl = this._createIconEl();
      el.insertBefore(this._icoEl, el.firstChild);
    } else if (!show && this._icoEl) {
      this._icoEl.remove();
      this._icoEl = null;
    }
  }

  destroy(): void {
    const el = this._element;
    if (!el) return;

    el.innerHTML = '';
    el.className = '';
    el.removeAttribute('role');

    this._element = null;
    this._icoEl = null;
    this._msgEl = null;
  }
}
